import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { getTheme, cardStyle } from '../../utils/theme';
import { PageHeader, Btn } from '../../components/common/UI';
import API from '../../utils/api';

const loadRazorpay = () =>
  new Promise((resolve) => {
    if (window.Razorpay) return resolve(true);
    const s = document.createElement('script');
    s.src = 'https://checkout.razorpay.com/v1/checkout.js';
    s.onload = () => resolve(true);
    s.onerror = () => resolve(false);
    document.body.appendChild(s);
  });

export default function PaymentPage() {
  const { user, darkMode } = useAuth();
  const t = getTheme(darkMode);
  const [loading, setLoading] = useState(false);
  const [success, setSuccess] = useState(null);
  const [error, setError] = useState('');
  const [tab, setTab] = useState('one-time'); // one-time | subscription

  const handleOneTimePayment = async (amount, type, referenceId, description) => {
    setLoading(true); setError('');
    const loaded = await loadRazorpay();
    if (!loaded) { setError('Razorpay SDK failed to load.'); setLoading(false); return; }

    try {
      const { data } = await API.post('/payment/create-order', { amount, type, referenceId });
      const { order, key } = data;

      const options = {
        key,
        amount: order.amount,
        currency: order.currency,
        name: 'MediCare+',
        description,
        order_id: order.id,
        image: '🏥',
        prefill: { name: user?.name, email: user?.email },
        theme: { color: '#0ea5e9' },
        handler: async (response) => {
          try {
            await API.post('/payment/verify', {
              razorpay_order_id: response.razorpay_order_id,
              razorpay_payment_id: response.razorpay_payment_id,
              razorpay_signature: response.razorpay_signature,
              type, referenceId,
            });
            setSuccess({ paymentId: response.razorpay_payment_id, amount, description });
          } catch { setError('Payment verification failed.'); }
        },
        modal: { ondismiss: () => setLoading(false) },
      };

      const rzp = new window.Razorpay(options);
      rzp.on('payment.failed', (resp) => {
        setError('Payment failed: ' + resp.error.description);
        setLoading(false);
      });
      rzp.open();
    } catch (e) {
      setError(e.response?.data?.error || 'Failed to create payment order.');
    }
    setLoading(false);
  };

  const handleSubscription = async (plan) => {
    setLoading(true); setError('');
    const loaded = await loadRazorpay();
    if (!loaded) { setError('Razorpay SDK failed to load.'); setLoading(false); return; }

    try {
      // Create plan then subscription
      const { data: planData } = await API.post('/payment/subscription/plan', {
        name: plan.name, amount: plan.amount, period: 'monthly', interval: 1,
      });
      const { data: subData } = await API.post('/payment/subscription/create', {
        planId: planData.plan.id, totalCount: 12,
      });

      const options = {
        key: subData.key,
        subscription_id: subData.subscription.id,
        name: 'MediCare+',
        description: plan.name + ' — Monthly Subscription',
        prefill: { name: user?.name, email: user?.email },
        theme: { color: '#0ea5e9' },
        handler: async (response) => {
          try {
            await API.post('/payment/subscription/verify', {
              razorpay_payment_id: response.razorpay_payment_id,
              razorpay_subscription_id: response.razorpay_subscription_id,
              razorpay_signature: response.razorpay_signature,
            });
            setSuccess({ paymentId: response.razorpay_payment_id, amount: plan.amount, description: plan.name + ' Subscription' });
          } catch { setError('Subscription verification failed.'); }
        },
        modal: { ondismiss: () => setLoading(false) },
      };

      const rzp = new window.Razorpay(options);
      rzp.open();
    } catch (e) {
      setError(e.response?.data?.error || 'Failed to start subscription.');
    }
    setLoading(false);
  };

  const plans = [
    { name: 'Basic Health Plan', amount: 299, features: ['2 consultations/month', 'Lab report upload', 'Medicine orders'] },
    { name: 'Premium Health Plan', amount: 799, features: ['Unlimited consultations', 'Priority booking', 'Home delivery', 'Emergency support'] },
    { name: 'Family Health Plan', amount: 1499, features: ['5 family members', 'Unlimited consultations', 'All premium features', 'Dedicated coordinator'] },
  ];

  const oneTimeItems = [
    { label: 'General Consultation', amount: 399, type: 'appointment', desc: '30-min doctor consultation' },
    { label: 'Video Consultation', amount: 499, type: 'appointment', desc: 'HD video call with specialist' },
    { label: 'Medicine Order', amount: 250, type: 'medicine', desc: 'Home delivery of prescription' },
  ];

  if (success) return (
    <div style={{ background: t.bg, minHeight: '100vh', padding: 24 }}>
      <div style={{ maxWidth: 500, margin: '60px auto', ...cardStyle(t), padding: 48, textAlign: 'center' }}>
        <div style={{ fontSize: '4rem', marginBottom: 16 }}>✅</div>
        <h2 style={{ color: t.text, fontWeight: 800, marginBottom: 8 }}>Payment Successful!</h2>
        <p style={{ color: t.textSub, marginBottom: 6 }}>{success.description}</p>
        <p style={{ color: '#10b981', fontWeight: 700, fontSize: 20 }}>₹{success.amount}</p>
        <p style={{ color: t.textSub, fontSize: 12, marginTop: 8 }}>Payment ID: {success.paymentId}</p>
        <div style={{ marginTop: 24, display: 'flex', gap: 12, justifyContent: 'center' }}>
          <Btn variant="outline" onClick={() => window.open(`/api/payment/invoice/demo`, '_blank')}>🧾 View Invoice</Btn>
          <Btn variant="primary" onClick={() => setSuccess(null)}>Make Another Payment</Btn>
        </div>
      </div>
    </div>
  );

  return (
    <div style={{ background: t.bg, minHeight: '100vh', padding: 24 }}>
      <div style={{ maxWidth: 860, margin: '0 auto' }}>
        <PageHeader title="💳 Payments & Billing" subtitle="Secure payments powered by Razorpay" darkMode={darkMode} />

        {error && <div style={{ background: '#fee2e2', color: '#991b1b', padding: '10px 16px', borderRadius: 10, marginBottom: 16, fontSize: 14 }}>{error}</div>}

        {/* Tabs */}
        <div style={{ display: 'flex', gap: 4, marginBottom: 24, background: darkMode ? '#1e293b' : '#f1f5f9', borderRadius: 12, padding: 4 }}>
          {[['one-time', '💳 One-time Payment'], ['subscription', '🔄 Subscriptions']].map(([k, label]) => (
            <button key={k} onClick={() => setTab(k)} style={{ flex: 1, padding: '10px 0', border: 'none', borderRadius: 10, cursor: 'pointer', fontWeight: 700, fontSize: 14, transition: 'all 0.2s', background: tab === k ? (darkMode ? '#334155' : 'white') : 'transparent', color: tab === k ? '#0ea5e9' : t.textSub, boxShadow: tab === k ? '0 1px 4px rgba(0,0,0,0.1)' : 'none' }}>
              {label}
            </button>
          ))}
        </div>

        {tab === 'one-time' && (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: 16 }}>
            {oneTimeItems.map(item => (
              <div key={item.label} style={{ ...cardStyle(t), padding: 24 }}>
                <div style={{ fontSize: 32, marginBottom: 12 }}>
                  {item.type === 'appointment' ? '🏥' : '💊'}
                </div>
                <div style={{ fontWeight: 700, fontSize: 16, color: t.text, marginBottom: 6 }}>{item.label}</div>
                <div style={{ color: t.textSub, fontSize: 13, marginBottom: 16 }}>{item.desc}</div>
                <div style={{ fontSize: 24, fontWeight: 800, color: '#0ea5e9', marginBottom: 16 }}>₹{item.amount}</div>
                <Btn variant="primary" disabled={loading} onClick={() => handleOneTimePayment(item.amount, item.type, null, item.label)} style={{ width: '100%' }}>
                  {loading ? 'Processing…' : 'Pay Now'}
                </Btn>
              </div>
            ))}
          </div>
        )}

        {tab === 'subscription' && (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))', gap: 16 }}>
            {plans.map((plan, i) => (
              <div key={plan.name} style={{ ...cardStyle(t), padding: 24, border: i === 1 ? '2px solid #0ea5e9' : undefined, position: 'relative' }}>
                {i === 1 && <div style={{ position: 'absolute', top: -12, left: '50%', transform: 'translateX(-50%)', background: '#0ea5e9', color: 'white', fontSize: 11, fontWeight: 700, padding: '3px 14px', borderRadius: 999 }}>POPULAR</div>}
                <div style={{ fontWeight: 700, fontSize: 16, color: t.text, marginBottom: 6 }}>{plan.name}</div>
                <div style={{ fontSize: 28, fontWeight: 800, color: '#0ea5e9', marginBottom: 4 }}>₹{plan.amount}<span style={{ fontSize: 13, fontWeight: 400, color: t.textSub }}>/mo</span></div>
                <ul style={{ padding: '12px 0 16px 0', margin: 0, listStyle: 'none' }}>
                  {plan.features.map(f => (
                    <li key={f} style={{ color: t.textSub, fontSize: 13, marginBottom: 6 }}>✓ {f}</li>
                  ))}
                </ul>
                <Btn variant={i === 1 ? 'primary' : 'outline'} disabled={loading} onClick={() => handleSubscription(plan)} style={{ width: '100%' }}>
                  {loading ? 'Processing…' : 'Subscribe'}
                </Btn>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
